# String utility module for formatting results

def format_number(n: float, decimals: int) -> str:
    # Simple formatting - just use f-string
    return f"{n:.{decimals}f}"

def repeat_text(text: str, times: int) -> str:
    result: str = ""
    i: int = 0
    while i < times:
        result = result + text
        i += 1
    return result

class TextFormatter:
    prefix: str

    def __init__(self, prefix: str):
        self.prefix = prefix

    def format_result(self, name: str, value: float) -> str:
        return f"{self.prefix}{name}: {value}"
